(()=>{'use strict';
const $=s=>document.querySelector(s);
const T=v=>String(v??'').trim();
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function css(){if($('#printStoreNameEdit296Css'))return;const st=document.createElement('style');st.id='printStoreNameEdit296Css';st.textContent='#doitPrintOverlay .storeNameEdit296{margin-top:4px;font-size:11px;font-weight:700;display:flex;gap:5px;align-items:center}#doitPrintOverlay .storeNameEdit296 input{height:25px;border:.5pt solid #000;padding:2px 5px;font:inherit;font-size:12px;font-weight:900;min-width:190px;background:#fff;color:#000}@media print{#doitPrintOverlay .storeNameEdit296{display:none!important}}';document.head.appendChild(st)}
function install(){const ov=$('#doitPrintOverlay');if(!ov)return;css();ov.querySelectorAll('.page').forEach((pg,idx)=>{if(pg.dataset.storeEdit296)return;const shop=pg.querySelector('.shop');if(!shop)return;pg.dataset.storeEdit296='1';const original=T(shop.textContent).replace(/^ร้าน\s*:\s*/,'');shop.dataset.originalStore=original;shop.dataset.printStore=original;const wrap=document.createElement('div');wrap.className='storeNameEdit296';wrap.innerHTML=`<span>ชื่อร้านบนใบปริ้น:</span><input type="text" value="${esc(original)}" aria-label="ชื่อร้านบนใบปริ้น">`;shop.insertAdjacentElement('afterend',wrap);const inp=wrap.querySelector('input');inp.addEventListener('input',()=>{const v=T(inp.value)||original;shop.dataset.printStore=v;shop.innerHTML='ร้าน: '+esc(v)});inp.addEventListener('change',()=>{if(!T(inp.value)){inp.value=original;shop.innerHTML='ร้าน: '+esc(original)}})})}
function boot(){install();const mo=new MutationObserver(()=>install());mo.observe(document.documentElement,{childList:true,subtree:true});setInterval(install,1000)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot,{once:true});else boot();
})();